   439→
   440→// This `Array.from` will build an array of elements from 1 to 99
   441→const buildPercentileReducers = (percentiles = [...Array.from({ length: 99 }, (_, i) => i + 1)]) => {
   442→  const percentileReducers: FieldReducerInfo[] = [];
   443→  const nth = (n: number) =>
   444→    n > 3 && n < 21 ? 'th' : n % 10 === 1 ? 'st' : n % 10 === 2 ? 'nd' : n % 10 === 3 ? 'rd' : 'th';
   445→
   446→  percentiles.forEach((p) => {
   447→    const percentile = p / 100;
   448→    const id = `p${p}`;
   449→    const name = `${p}${nth(p)} %`;
   450→    const description = `${p}${nth(p)} percentile value`;
   451→
   452→    percentileReducers.push({
   453→      id: id,
   454→      name: name,
   455→      description: description,
   456→      standard: false,
   457→      reduce: (field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs => {
   458→        return { [id]: calculatePercentile(field, percentile, ignoreNulls, nullAsZero) };
   459→      },
   460→      preservesUnits: true,
   461→    });
   462→  });
   463→  return percentileReducers;
   464→};
   465→
   466→// Used for test cases
   467→export const defaultCalcs: FieldCalcs = {
   468→  sum: 0,
   469→  max: -Number.MAX_VALUE,
   470→  min: Number.MAX_VALUE,
   471→  logmin: Number.MAX_VALUE,
   472→  mean: null,
   473→  last: null,
   474→  first: null,
   475→  lastNotNull: null,
   476→  firstNotNull: null,
   477→  count: 0,
   478→  nonNullCount: 0,
   479→  allIsNull: true,
   480→  allIsZero: true,
   481→  range: null,
   482→  diff: null,
   483→  delta: 0,
   484→  step: Number.MAX_VALUE,
   485→  diffperc: 0,
   486→  // Just used for calculations -- not exposed as a stat
   487→  previousDeltaUp: true,
   488→};
   489→
   490→export function doStandardCalcs(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   491→  const calcs: FieldCalcs = { ...defaultCalcs };
   492→
   493→  const data = field.values;
   494→
   495→  // early return for undefined / empty series
   496→  if (!data) {
   497→    return calcs;
   498→  }
   499→
   500→  const isNumberField = field.type === FieldType.number || field.type === FieldType.time;
   501→
   502→  for (let i = 0; i < data.length; i++) {
   503→    let currentValue = data[i];
   504→
   505→    if (i === 0) {
   506→      calcs.first = currentValue;
   507→    }
   508→
   509→    calcs.last = currentValue;
   510→
   511→    if (currentValue == null) {
   512→      if (ignoreNulls) {
   513→        continue;
   514→      }
   515→      if (nullAsZero) {
   516→        currentValue = 0;
   517→      }
   518→    }
   519→
   520→    calcs.count++;
   521→
   522→    if (currentValue != null && !Number.isNaN(currentValue)) {
   523→      // null || undefined || NaN
   524→      const isFirst = calcs.firstNotNull === null;
   525→      if (isFirst) {
   526→        calcs.firstNotNull = currentValue;
   527→      }
   528→
   529→      if (isNumberField) {
   530→        calcs.sum += currentValue || 0;
   531→        calcs.allIsNull = false;
   532→        calcs.nonNullCount++;
   533→
   534→        if (!isFirst) {
   535→          const step = currentValue - calcs.lastNotNull!;
   536→          if (calcs.step > step) {
   537→            calcs.step = step; // the minimum interval
   538→          }
   539→
   540→          if (calcs.lastNotNull! > currentValue) {
   541→            // counter reset
   542→            calcs.previousDeltaUp = false;
   543→          } else {
   544→            if (calcs.previousDeltaUp) {
   545→              calcs.delta += step; // normal increment
   546→            }
   547→            calcs.previousDeltaUp = true;
   548→          }
   549→        }
   550→
   551→        if (currentValue > calcs.max) {
   552→          calcs.max = currentValue;
   553→        }
   554→
   555→        if (currentValue < calcs.min) {
   556→          calcs.min = currentValue;
   557→        }
   558→
   559→        if (currentValue < calcs.logmin && currentValue > 0) {
   560→          calcs.logmin = currentValue;
   561→        }
   562→      }
   563→
   564→      if (currentValue !== 0) {
   565→        calcs.allIsZero = false;
   566→      }
   567→
   568→      calcs.lastNotNull = currentValue;
   569→    }
   570→  }
   571→
   572→  if (calcs.max === -Number.MAX_VALUE) {
   573→    calcs.max = null;
   574→  }
   575→
   576→  if (calcs.min === Number.MAX_VALUE) {
   577→    calcs.min = null;
   578→  }
   579→
   580→  if (calcs.step === Number.MAX_VALUE) {
   581→    calcs.step = null;
   582→  }
   583→
   584→  if (calcs.nonNullCount > 0) {
   585→    calcs.mean = calcs.sum! / calcs.nonNullCount;
   586→  }
   587→
   588→  if (calcs.allIsNull) {
   589→    calcs.allIsZero = false;
   590→  }
   591→
   592→  if (calcs.max !== null && calcs.min !== null) {
   593→    calcs.range = calcs.max - calcs.min;
   594→  }
   595→
   596→  if (isNumber(calcs.firstNotNull) && isNumber(calcs.lastNotNull)) {
   597→    calcs.diff = calcs.lastNotNull - calcs.firstNotNull;
   598→  }
   599→
   600→  if (isNumber(calcs.firstNotNull) && isNumber(calcs.diff)) {
   601→    calcs.diffperc = (calcs.diff / calcs.firstNotNull) * 100;
   602→  }
   603→
   604→  return calcs;
   605→}
   606→
   607→function calculateFirst(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   608→  return { first: field.values[0] };
   609→}
   610→
   611→function calculateFirstNotNull(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   612→  const data = field.values;
   613→  for (let idx = 0; idx < data.length; idx++) {
   614→    const v = data[idx];
   615→    if (v != null && !Number.isNaN(v)) {
   616→      return { firstNotNull: v };
   617→    }
   618→  }
   619→  return { firstNotNull: null };
   620→}
   621→
   622→function calculateLast(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   623→  const data = field.values;
   624→  return { last: data[data.length - 1] };
   625→}
   626→
   627→function calculateLastNotNull(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   628→  const data = field.values;
   629→  let idx = data.length - 1;
   630→  while (idx >= 0) {
   631→    const v = data[idx--];
   632→    if (v != null && !Number.isNaN(v)) {
   633→      return { lastNotNull: v };
   634→    }
   635→  }
   636→  return { lastNotNull: null };
   637→}
   638→
   639→/** Calculates standard deviation and variance */
   640→function calculateStdDev(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   641→  // Only support number fields
   642→  if (!(field.type === FieldType.number || field.type === FieldType.time)) {
   643→    return { variance: 0, stdDev: 0 };
   644→  }
   645→
   646→  let squareSum = 0;
   647→  let runningMean = 0;
   648→  let runningNonNullCount = 0;
   649→  const data = field.values;
   650→  for (let i = 0; i < data.length; i++) {
   651→    const currentValue = data[i];
   652→    if (currentValue != null) {
   653→      runningNonNullCount++;
   654→      let _oldMean = runningMean;
